Here's how you can implement a `batch_write` function in JavaScript to create multiple files with the specified content:

### Node.js Implementation (using `fs` module)
```javascript
const fs = require('fs');
const path = require('path');

function batch_write(files) {
  files.forEach(file => {
    // Ensure the directory exists (create if not)
    const dir = path.dirname(file.path);
    if (dir && !fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    // Write the file
    fs.writeFileSync(file.path, file.content, 'utf8');
    console.log(`Created: ${file.path}`);
  });
}

// Usage
batch_write([
  { "path": "batch-oauth-1.js", "content": "console.log(1)" },
  { "path": "batch-oauth-2.js", "content": "console.log(2)" }
]);
```

### Browser Implementation (using File System Access API)
If you're working in a browser environment with the File System Access API (Chrome/Edge only):

```javascript
async function batch_write(files) {
  for (const file of files) {
    try {
      const handle = await window.showSaveFilePicker({
        suggestedName: file.path,
        types: [{
          description: 'JavaScript Files',
          accept: {'text/javascript': ['.js']},
        }],
      });

      const writable = await handle.createWritable();
      await writable.write(file.content);
      await writable.close();
      console.log(`Created: ${file.path}`);
    } catch (err) {
      console.error(`Failed to create ${file.path}:`, err);
    }
  }
}

// Usage
batch_write([
  { "path": "batch-oauth-1.js", "content": "console.log(1)" },
  { "path": "batch-oauth-2.js", "content": "console.log(2)" }
]);
```

### Notes:
1. The Node.js version will create files in the current working directory of your script.
2. The browser version requires user interaction (file picker) for each file.
3. For production use, you might want to add error handling and async/await for the Node.js version if dealing with many files.

